// Harn syntax highlighting for mdBook's bundled highlight.js.
//
// Keyword and builtin lists are generated by
// `harn dump-highlight-keywords` into docs/theme/harn-keywords.js and
// read off `window.__HARN_KEYWORDS`. The structural rules (strings,
// numbers, comments, operators) live here because they change rarely
// and are small enough to hand-maintain.
//
// Load order (see mdBook-generated index.html):
//   1. highlight.js        — registers default languages
//   2. book.js             — calls hljs.highlightBlock on every <code>
//   3. harn-keywords.js    — sets window.__HARN_KEYWORDS
//   4. harn-hljs.js (this) — registers `harn`, then re-highlights any
//                            .language-harn blocks that book.js already
//                            processed before the language existed.
(function () {
  if (typeof window === "undefined" || !window.hljs) {
    return;
  }
  var kw = window.__HARN_KEYWORDS;
  if (!kw) {
    // If harn-keywords.js failed to load, fall back to a minimal keyword
    // set so blocks at least get keyword coloring. Regenerate with
    // `make gen-highlight` to restore the full list.
    kw = {
      keyword:
        "pipeline fn let var if else for in while match try catch throw finally return import struct enum interface impl pub type",
      literal: "true false nil",
      built_in: "println log read_file write_file llm_call agent_loop",
    };
  }

  hljs.registerLanguage("harn", function (hljs) {
    var KEYWORDS = {
      keyword: kw.keyword,
      literal: kw.literal,
      built_in: kw.built_in,
    };

    // Interpolated strings: "hello ${name}" — Harn uses double-quoted
    // strings with ${...} interpolation. Single quotes are NOT string
    // delimiters in Harn, so only match double quotes.
    var INTERPOLATION = {
      className: "subst",
      begin: /\$\{/,
      end: /\}/,
      keywords: KEYWORDS,
      contains: [], // filled in below to allow recursive expression content
    };
    var STRING = {
      className: "string",
      begin: '"',
      end: '"',
      illegal: "\\n",
      contains: [{ begin: "\\\\." }, INTERPOLATION],
    };

    // Duration literals: 500ms, 2s, 30m, 1h (integer or float mantissa).
    // Must come before the generic NUMBER rule so the suffix is captured.
    var DURATION = {
      className: "number",
      begin: /\b\d+(?:\.\d+)?(?:ms|s|m|h)\b/,
      relevance: 0,
    };

    var NUMBER = {
      className: "number",
      variants: [
        { begin: /\b\d+\.\d+(?:[eE][+-]?\d+)?/ },
        { begin: /\b\d+(?:[eE][+-]?\d+)?/ },
      ],
      relevance: 0,
    };

    // CamelCase identifiers — Harn convention for types, enums, structs,
    // interfaces, and Result constructors (Ok/Err).
    var TYPE = {
      className: "type",
      begin: /\b[A-Z][A-Za-z0-9_]*\b/,
      relevance: 0,
    };

    var mainContains = [
      hljs.C_LINE_COMMENT_MODE,
      hljs.C_BLOCK_COMMENT_MODE,
      STRING,
      DURATION,
      NUMBER,
      TYPE,
      // Function definition title
      {
        className: "title.function",
        beginKeywords: "fn pipeline",
        end: /[(\s]/,
        excludeEnd: true,
        contains: [{ begin: /[a-z_][A-Za-z0-9_]*/ }],
        relevance: 0,
      },
    ];

    // Allow interpolated expressions to contain strings, numbers, etc.
    INTERPOLATION.contains = mainContains;

    return {
      name: "Harn",
      aliases: ["harn"],
      keywords: KEYWORDS,
      contains: mainContains,
    };
  });

  // Re-highlight any blocks book.js already processed before our
  // language was registered. Works for both the old `highlightBlock`
  // API mdBook uses and the modern `highlightElement`.
  function rehighlightHarnBlocks() {
    var blocks = document.querySelectorAll("code.language-harn");
    blocks.forEach(function (block) {
      // Clear highlight.js state so it'll re-process this element.
      block.removeAttribute("data-highlighted");
      // Restore the original source text: book.js may have injected
      // span-wrapped highlight output, which we don't want to re-parse.
      // The textContent getter gives us the plain source.
      var src = block.textContent;
      block.innerHTML = "";
      block.textContent = src;
      if (typeof hljs.highlightElement === "function") {
        hljs.highlightElement(block);
      } else if (typeof hljs.highlightBlock === "function") {
        hljs.highlightBlock(block);
      }
      block.classList.add("hljs");
    });
  }

  if (document.readyState === "loading") {
    document.addEventListener("DOMContentLoaded", rehighlightHarnBlocks);
  } else {
    rehighlightHarnBlocks();
  }
})();
